  ('TDE.9.A.1.12', 'Türk Dili ve Edebiyatı', 9, 1, 'Okuma', 'Metinden hareketle dil bilgisi çalışmaları yapar.', ''),
  ('TDE.9.A.1.13', 'Türk Dili ve Edebiyatı', 9, 1, 'Okuma', 'Şiiri farklı metinlerle karşılaştırır.', ''),
  ('TDE.9.A.2.1', 'Türk Dili ve Edebiyatı', 9, 1, 'Okuma', 'Öyküleyici metinde sözcük ve söz öbeklerinin anlam özelliklerini belirler.', ''),
  ('TDE.9.A.2.2', 'Türk Dili ve Edebiyatı', 9, 1, 'Okuma', 'Öyküleyici metinde tema ve konuyu belirler.', ''),
  ('TDE.9.A.2.3', 'Türk Dili ve Edebiyatı', 9, 1, 'Okuma', 'Öyküleyici metinde anlam ilişkilerini belirler.', ''),
