  ('DYS.DO.6.1.001', 'Türkçe', 6, 6, 'Ünite 6', 'Kelimelerin kökünü ve ekini ayırt eder.', ''),
  ('DYS.DO.6.1.1.001', 'Türkçe', 6, 6, 'Ünite 6', 'Yapım eklerinin işlevlerini ayırt eder. (Yapım ve çekim eki ayrımı üzerinde durulur. Yapım ekleri ezberletilmez, sezdirilir. Kelime türetmenin mantığı kavratılır.)', ''),
  ('DYS.KY.6.1.001', 'Türkçe', 6, 6, 'Ünite 6', 'Ses olaylarına (ünlü düşmesi, ünsüz benzeşmesi, ünsüz yumuşaması, ünlü daralması, ünlü türemesi ve ünsüz türemesi) uğrayan söz varlığı ve dil yapılarını doğru kullanır.', ''),
  ('DYS.DO.6.3.001', 'Türkçe', 6, 6, 'Ünite 6', 'Özne-yüklem uyumunu ayırt eder. Öğrencinin özne-yüklem uyumunu sağlamada sorun yaşaması hâlinde öğretmen anlama çalışmalarında bu uyuma dikkat çeker.', ''),
  ('DYS.DO.6.4.001', 'Türkçe', 6, 6, 'Ünite 6', 'Sebep işlevli söz varlığını/dil yapılarını (çünkü, bu nedenle, için, diye, demek, demek ki, -DIğI için, ...-sI yüzünden/sebebiyle, ...-nın yüzünden/sonucunda vb.) belirler.', ''),
  ('DYS.KY.6.3.001', 'Türkçe', 6, 6, 'Ünite 6', 'Sebep işlevli söz varlığını/dil yapılarını (çünkü, bu nedenle, için, diye, demek, demek ki, -DIğI için, ...-sI yüzünden/sebebiyle, ...-nın yüzünden/sonucunda vb.) kullanır.', ''),
  ('DYS.DO.6.5.001', 'Türkçe', 6, 6, 'Ünite 6', 'Amaç ifade etme işlevli söz varlığını/dil yapılarını (-mAk için, amacıyla, için, -mAsI için, niye, niçin, diye, üzere vb.) belirler.', ''),
  ('DYS.KY.6.4.001', 'Türkçe', 6, 6, 'Ünite 6', 'Amaç ifade etme işlevli söz varlığını/dil yapılarını (-mAk için, amacıyla, için, -mAsI için, niye, niçin, diye, üzere vb.) kullanır.', ''),
  ('DYS.DO.6.6.001', 'Türkçe', 6, 6, 'Ünite 6', 'Şart işlevli söz varlığını/dil yapılarını (-sA, ise, -DI mI, -DIkçA, -IncA ama, yalnız, lazım, eğer, şayet, ki, mutlaka, kesinlikle, şu şartla, illa vb.) belirler.', ''),
  ('DYS.KY.6.5.001', 'Türkçe', 6, 6, 'Ünite 6', 'Şart işlevli söz varlığını/dil yapılarını (-sA, ise, -DI mI, -DIkçA, -IncA ama, yalnız, lazım, eğer, şayet, ki, mutlaka, kesinlikle, şu şartla, illa vb.) kullanır.', ''),
  ('DYS.DO.6.7.001', 'Türkçe', 6, 6, 'Ünite 6', 'Zıtlık işlevli söz varlığını (ama, fakat, lakin, aksine, ancak, yoksa, aslında, hem ... hem de ..., hâlbuki, tam tersine vb.) belirler.', ''),
  ('DYS.KY.6.6.001', 'Türkçe', 6, 6, 'Ünite 6', 'Zıtlık işlevli söz varlığını (ama, fakat, lakin, aksine, ancak, yoksa, aslında, hem ... hem de ..., hâlbuki, tam tersine vb.) kullanır.', ''),
  ('DYS.DO.6.8.001', 'Türkçe', 6, 6, 'Ünite 6', 'Olumsuzluk işlevli söz varlığını/dil yapılarını (hayır, yok, asla, değil, olmaz, maalesef, ne yazık ki, -sIz, -mA, -mAz vb.) belirler.', ''),
  ('DYS.KY.6.7.001', 'Türkçe', 6, 6, 'Ünite 6', 'Olumsuzluk işlevli söz varlığını/dil yapılarını (hayır, yok, asla, değil, olmaz, maalesef, ne yazık ki, -sIz, -mA, -mAz vb.) kullanır.', ''),
  ('DYS.DO.6.9.001', 'Türkçe', 6, 6, 'Ünite 6', 'Karşılaştırma işlevli söz varlığını/dil yapılarını (-DAn daha, ise, işin kötüsü, her ne kadar, nasıl, neredeyse vb.) belirler.', ''),
  ('DYS.KY.6.8.001', 'Türkçe', 6, 6, 'Ünite 6', 'Karşılaştırma işlevli söz varlığını/dil yapılarını (-DAn daha, ise, işin kötüsü, her ne kadar, nasıl, neredeyse vb.) kullanır.', ''),
  ('DYS.DO.6.10.001', 'Türkçe', 6, 6, 'Ünite 6', 'Benzerlik işlevli söz varlığını/dil yapılarını (âdeta, benzer, benzer şekilde, aynı, aynı şekilde, -mIş gibi, sanki, -msI vb.) belirler.', ''),
  ('DYS.KY.6.9.001', 'Türkçe', 6, 6, 'Ünite 6', 'Benzerlik işlevli söz varlığını/dil yapılarını (âdeta, benzer, benzer şekilde, aynı, aynı şekilde, -mIş gibi, sanki, -msI vb.) kullanır.', ''),
  ('DYS.DO.6.11.001', 'Türkçe', 6, 6, 'Ünite 6', 'Dinlediklerinde/izlediklerinde ve okuduklarında Türkçenin doğru, güzel ve etkili kullanıldığı cümleler belirler.', ''),
