  ('T.D.7.6.001', 'Türkçe', 7, 7, 'Ünite 7', 'Resim, fotoğraf, tablo, grafik (pasta, sütun, çizgi vb.), grafik simge, harita ve kroki, karikatürden yararlanılır.', ''),
  ('T.D.7.9.001', 'Türkçe', 7, 7, 'Ünite 7', 'Dinlediğindeki/izlediğindeki içeriği önem, doğruluk, güvenirlik, öncelik ve sonralık bakımından karşılaştırır.', ''),
  ('T.D.7.14.001', 'Türkçe', 7, 7, 'Ünite 7', 'Sıralı/kronolojik, açıklayıcı, karşılaştırma/zıtlık, sebep-sonuç ve problem-çözüm metin yapılarına yönelik çalışmalar yapılır.', ''),
  ('T.D.7.17.001', 'Türkçe', 7, 7, 'Ünite 7', 'Düşünceyi geliştirme yollarından tanımlama, karşılaştırma, benzetme, örneklendirme, tanık gösterme ve sayısal verilerden yararlanmayı belirlemeye yönelik çalışmalar yapılır.', ''),
  ('T.D.7.18.001', 'Türkçe', 7, 7, 'Ünite 7', 'Söz sanatlarından kişileştirme, konuşturma, benzetme, karşıtlık ve abartmayı belirlemeye yönelik çalışmalar yapılır.', ''),
  ('T.D.7.19.001', 'Türkçe', 7, 7, 'Ünite 7', 'Karşılıkta bulunma, tutarlılık, toplumsal kanıt, sevgi (hoşlanma), otorite, kıtlık (azlık), karşıtlık ve uzlaşma tekniklerini belirler.', ''),
